     1→@using NonFactors.Mvc.Grid;
     2→@model Firstronic.Framework.Account.tbl_AspNetPosition_FULL
     3→
     4→@{
     5→  bool isNew = !(Model != null && Model.PositionID > 0);
     6→}
     7→<div class="md-card">
     8→  <div class="md-card-toolbar">
     9→    <h3 class="md-card-toolbar-heading-text">Manage AspNetPosition: @Model.Position</h3>
    10→  </div>
    11→  <div class="md-card-content">
    12→    @using (Html.BeginForm())
    13→    {
    14→
    15→      @Html.AntiForgeryToken()
    16→      @Html.ValidationSummary("", new { @class = "hide" })
    17→
    18→      @Html.HiddenFor(y => y.PositionID, new { id = "txtPositionID" })
    19→
    20→      <ul class="uk-tab uk-tab-grid" data-uk-tab="{connect:'#tabs_4'}">
    21→        <li class="uk-width-1-3 uk-active" aria-expanded="true"><a href="#">General</a></li>
    22→        @if (!isNew)
    23→        {
    24→          <li class="uk-width-1-3" aria-expanded="false"><a href="#">Roles</a></li>
    25→          <li class="uk-width-1-3" aria-expanded="false"><a href="#">Users</a></li>
    26→        }
    27→      </ul>
    28→
    29→      <ul id="tabs_4" class="uk-switcher uk-margin">
    30→        <li aria-hidden="false" class="uk-active">
    31→          <div class="uk-grid pt-3">
    32→            <div class="uk-width-1-1">
    33→              <div class="uk-form-row">
    34→                @Html.LabelFor(y => y.Position)
    35→                @Html.TextBoxFor(y => y.Position, new { @class = "md-input" })
    36→              </div>
    37→            </div>
    38→          </div>
    39→        </li>
    40→        <li aria-hidden="true">
    41→          @Html.AjaxGrid(Url.Action("GetRoles", "Position", new { id = Model.PositionID }))
    42→
    43→          @{
    44→            System.Data.SqlClient.SqlParameter[] Parameters = new System.Data.SqlClient.SqlParameter[]
    45→            {
    46→              new System.Data.SqlClient.SqlParameter("@PositionID",System.Data.SqlDbType.Int){Value = Model.PositionID }
    47→            };
    48→
    49→            var rolesavailables = Firstronic.Framework.Queries.GetSelectedFromQuery($@"SELECT [Id],[Name] FROM [AspNetRoles] WHERE Id not in (Select RolID from AspNetPositionRoles where PositionID=@PositionID) Order by Name asc", Parameters);
    50→
    51→            if (rolesavailables.Count() > 0)
    52→            {
    53→              <div class="p-0 input-group mb-3 mn-r-10">
    54→                @Html.Label("Roles", new { @class = "m-0 fs-14" })
    55→                @Html.DropDownList("Roles", (IEnumerable<SelectListItem>)rolesavailables, new { @class = "md-input", id = "ddlRoles" })
    56→              </div>
    57→
    58→              <div class="p-0 input-group mb-3 mn-r-10">
    59→                <input id="btnAdd" type="button" value="Add" class="md-btn md-btn-primary md-btn-small" />
    60→              </div>
    61→
    62→              <script type="text/javascript" nonce="@Html.ScriptNonce()">
    63→                $(document).on('click', '#btnAdd', function (e) {
    64→                  e.preventDefault();
    65→
    66→                  var vRolID = $("#ddlRoles").val();
    67→                  var vPostionID = $("#txtPositionID").val();
    68→
    69→                  var req = { vRolID: vRolID, vPostionID: vPostionID };
    70→
    71→                  ajaxfnc(req, vRolID);
    72→                });
    73→
    74→                function updateStages() {
    75→                  var grid = new MvcGrid(document.querySelector('#mvcRoles'));
    76→                  grid.requestType = 'post';
    77→                  grid.reload();
    78→                };
    79→
    80→                function ajaxfnc(column, vRolID) {
    81→                  $.ajax({
    82→                    type: "POST",
    83→                    url: "/Manage/Position/AddRoles",
    84→                    async: false,
    85→                    contentType: "application/json; charset=utf-8",
    86→                    data: JSON.stringify(column),
    87→                    success: function () {
    88→                      $("#ddlRoles option[value='" + vRolID + "']").remove();
    89→
    90→                      var length = $('#ddlRoles > option').length;
    91→
    92→                      if (length < 1) { $("#ddlRoles").remove() };
    93→
    94→                      updateStages();
    95→                    }
    96→                  })
    97→                };
    98→
    99→                $(document).on('click', '#mvcRoles>table>tbody>tr>td>a.delRow', function (e) {
   100→                  e.preventDefault(); // <------------------ stop default behaviour of button
   101→                  var target = $(this).attr("href");
   102→
   103→                  $.ajax({
   104→                    type: "POST",
   105→                    url: target,
   106→                    async: false,
   107→                    contentType: "application/json; charset=utf-8",
   108→                    success: function () {
   109→                      // Reload Grid
   110→                      updateStages();
   111→                    }
   112→                  })
   113→                });
   114→
   115→              </script>
   116→            }
   117→          }
   118→        </li>
   119→        <li aria-hidden="true">
   120→          @Html.AjaxGrid(Url.Action("GetUsers", "Position", new { id = Model.PositionID }))
   121→
   122→          @{
   123→            var usersavailables = Firstronic.Framework.Functions.Queries.GetSelectedFromQuery($@"SELECT [Id],CONCAT([Name],' - ',[Badge],' - ',[Username]) as Name FROM [AspNetUsers] WHERE IsActive = 1 Order by Name");
   124→
   125→            if (usersavailables.Count() > 0)
   126→            {
   127→              <div class="p-0 input-group mb-3 mn-r-10">
   128→                @Html.Label("Users", new { @class = "m-0 fs-14" })
   129→                @Html.DropDownList("Users", (IEnumerable<SelectListItem>)usersavailables, new { @class = "md-input", id = "ddlUsers" })
   130→              </div>
   131→              <script type="text/javascript" nonce="@Html.ScriptNonce()">
   132→                $("#ddlUsers").select2();
   133→              </script>
   134→
   135→              <div class="p-0 input-group mb-3 mn-r-10">
   136→                <input id="btnAddUser" type="button" value="Add" class="md-btn md-btn-primary md-btn-small" />
   137→              </div>
   138→
   139→              <script type="text/javascript" nonce="@Html.ScriptNonce()">
   140→                $(document).on('click', '#btnAddUser', function (e) {
   141→                  e.preventDefault();
   142→
   143→                  var vUserId = $("#ddlUsers").val();
   144→                  var vPostionID = $("#txtPositionID").val();
   145→
   146→                  var req = { vUserId: vUserId, vPostionID: vPostionID };
   147→
   148→                  $.ajax({
   149→                    type: "POST",
   150→                    url: "/Manage/Position/AddUsers",
   151→                    async: false,
   152→                    contentType: "application/json; charset=utf-8",
   153→                    data: JSON.stringify(req),
   154→                    success: function () {
   155→                      $("#ddlUsers option[value='" + vUserId + "']").remove();
   156→
   157→                      var length = $('#ddlUsers > option').length;
   158→
   159→                      updateUsers();
   160→                    }
   161→                  })
   162→                });
   163→
   164→                function updateUsers() {
   165→                  var grid = new MvcGrid(document.querySelector('#mvcUsers'));
   166→                  grid.requestType = 'post';
   167→                  grid.reload();
   168→                };
   169→
   170→
   171→                $(document).on('click', '#mvcUsers>table>tbody>tr>td>a.delRow', function (e) {
   172→                  e.preventDefault(); // <------------------ stop default behaviour of button
   173→                  var target = $(this).attr("href");
   174→
   175→                  $.ajax({
   176→                    type: "POST",
   177→                    url: target,
   178→                    async: false,
   179→                    contentType: "application/json; charset=utf-8",
   180→                    success: function () {
   181→                      // Reload Grid
   182→                      updateUsers();
   183→                    }
   184→                  })
   185→                });
   186→
   187→              </script>
   188→            }
   189→          }
   190→        </li>
   191→      </ul>
   192→
   193→      <div class="uk-clearfix md-card-overlay-header mn-t-25">
   194→        <a class="md-btn md-btn-primary md-btn-small" href="@Url.Action("Index", "Position")">
   195→          <i class="fa fa-arrow-left mr-1 fs-12"></i> @Resources.Actions.Back
   196→        </a>
   197→
   198→        <button type="submit" name="action:@(isNew ? "Create": "Edit")" class="md-btn md-btn-primary md-btn-small">
   199→          <i class="fa fa-save mr-1 fs-14"></i> @Resources.Actions.Save
   200→        </button>
   201→
   202→        <button type="submit" name="action:Delete" class="md-btn md-btn-danger md-btn-small">
   203→          <i class="fa fa-trash mr-1 fs-14"></i> @Resources.Actions.Delete
   204→        </button>
   205→
   206→        <a class="md-btn md-btn-primary md-btn-small" href="@Url.Action("Create", "Position")">
   207→          <i class="fa fa-plus mr-1 fs-12"></i> @Resources.Actions.Add_New
   208→        </a>
   209→      </div>
   210→    }
   211→  </div>
   212→</div>
